fun solve(value: Array<Long>, limit: Array<Long>): Long {
    // Sort elements by value in descending order
    val sortedIndices = value.indices.sortedWith(compareBy({ value[it] }, { -it }))

    // Use a priority queue (max heap) to keep track of active elements
    // We'll use a min-heap to simulate a max-heap by storing negative values
    val activeHeap = PriorityQueue<Long>(compareBy { -it })

    // Keep track of the current number of active elements
    var activeCount = 0

    // Keep track of the total sum
    var totalSum = 0L

    // Keep track of which elements are still active
    val activeSet = mutableSetOf<Int>()

    for (i in sortedIndices) {
        // Check if the current element can be activated
        if (activeCount < limit[i]) {
            // Add the value to the total sum
            totalSum += value[i]

            // Add the element to the active set
            activeSet.add(i)

            // Add the value to the active heap
            activeHeap.add(value[i])

            // Increment the active count
            activeCount++
        }
    }

    // Now, we need to remove elements that become inactive based on the current active count
    // We'll iterate through all elements and check if they should be deactivated
    for (i in 0 until value.size) {
        if (activeSet.contains(i) && limit[i] <= activeCount) {
            // Remove the element from the active set
            activeSet.remove(i)

            // Remove the value from the active heap
            activeHeap.remove(value[i])
        }
    }

    // The total sum is the sum of all values in the active heap
    return activeHeap.sum()
}
